import React, { createContext, useContext, useState, useEffect } from 'react';

interface LanguageContextType {
  language: 'pt' | 'en' | 'es';
  setLanguage: (lang: 'pt' | 'en' | 'es') => void;
}

const LanguageContext = createContext<LanguageContextType | null>(null);

export const LanguageProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [language, setLanguage] = useState<'pt' | 'en' | 'es'>(() => {
    return (localStorage.getItem('language') as 'pt' | 'en' | 'es') || 'pt';
  });

  useEffect(() => {
    localStorage.setItem('language', language);

    // Trigger automatic translation when language changes
    if (typeof window !== 'undefined' && window.autoTranslator) {
      window.autoTranslator.setLanguage(language);
    }
  }, [language]);

  return (
    <LanguageContext.Provider value={{ language, setLanguage }}>
      {children}
    </LanguageContext.Provider>
  );
};

export const useLanguage = () => {
  const context = useContext(LanguageContext);
  if (!context) {
    throw new Error('useLanguage must be used within a LanguageProvider');
  }
  return context;
};

// Add autoTranslator to window object
declare global {
  interface Window {
    autoTranslator?: any;
  }
}
